36	void nccl_check(ncclResult_t status, const char *file, int line) {
37	    if (status != ncclSuccess) {
38	        printf("[NCCL ERROR] at file %s:%d:\n%s\n", file, line, ncclGetErrorString(status));
39	        exit(EXIT_FAILURE);
40	    }
