45	void mpi_check(int status, const char *file, int line) {
46	    if (status != MPI_SUCCESS) {
47	        char mpi_error[4096];
48	        int mpi_error_len = 0;
49	        assert(MPI_Error_string(status, &mpi_error[0], &mpi_error_len) == MPI_SUCCESS);
