60	// Parameters specific to training on multiple GPUs.
61	typedef struct {
62	    int process_rank;      // Rank of this process among all processes. 0 if no multi-GPU.
63	    int num_processes;     // Total number of processes. 1 if no multi-GPU.
64	    int local_device_idx;  // This process GPU index on current machine. 0 if no multi-GPU.
65	
66	    // Zero Redundancy Optimizer stage - https://fairscale.readthedocs.io/en/stable/deep_dive/oss_sdp_fsdp.html
67	    // 0-Disabled
68	    // 1-Optimizer State Sharding (OSS)
69	    // 2-Optimizer + Gradient State Sharding (SDP)
70	    // 3-Optimizer + Gradient + Horizontal Model Sharding (FSDP)
71	    int zero_stage;
72	    size_t shard_num_parameters;
73	#ifdef MULTI_GPU
74	    ncclComm_t nccl_comm;       // NCCL communication primitive, used for collective multi-GPU work.
75	    cudaStream_t nccl_stream;   // CUDA Stream to perform NCCL operations.
76	    cudaEvent_t compute_nccl_sync; // Event used to synchronize NCCL with the compute
77	    float* unified_buffer;
