111	// Same as get_nccl_id_via_tcp but for Windows
112	ncclUniqueId get_nccl_id_via_tcp_windows(MultiGpuConfig* result, const char* server_ip) {
113	    ncclUniqueId nccl_id;
114	
115	    int SERVER_PORT = 12345;  // hardcoded an arbitrary port number between 1024 and 49151 (registered ports)
116	    WSADATA wsaData;
117	    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
118	        printf("WSAStartup failed");
119	        exit(EXIT_FAILURE);
120	    }
121	
122	    if (result->process_rank == 0) {
123	        ncclCheck(ncclGetUniqueId(&nccl_id));
124	
125	        int MAX_CLIENTS = result->num_processes - 1;
126	        SOCKET client_sockets[MAX_CLIENTS];
127	        int num_clients = 0;
128	        SOCKET server_socket, new_socket;
129	        struct sockaddr_in address;
130	        int addrlen = sizeof(address);
131	
132	        // Step 1) create a server TCP socket
133	        if ((server_socket = socket(AF_INET, SOCK_STREAM, 0)) == INVALID_SOCKET) {
134	            printf("Socket failed");
135	            WSACleanup();
136	            exit(EXIT_FAILURE);
137	        }
138	
139	        // Step 2) set the server address and port
140	        address.sin_family = AF_INET;  // IPv4
141	        address.sin_addr.s_addr = inet_addr(server_ip);
142	        address.sin_port = htons(SERVER_PORT);
143	
144	        // Step 3) bind the socket to the address and port
145	        if (bind(server_socket, (struct sockaddr *)&address, sizeof(address)) == SOCKET_ERROR) {
146	            printf("Bind failed");
147	            closesocketCheck(server_socket);
148	            WSACleanup();
149	            exit(EXIT_FAILURE);
150	        }
151	
152	        // Step 4) MAX_CLIENTS specifies the maximum number of clients that can be queued for this server
153	        if (listen(server_socket, MAX_CLIENTS) == SOCKET_ERROR) {
154	            printf("Listen failed");
155	            closesocketCheck(server_socket);
156	            WSACleanup();
157	            exit(EXIT_FAILURE);
158	        }
159	
160	        // Step 5) accept connections from clients
161	        printf("Waiting for clients to connect...\n");
162	        while (num_clients < MAX_CLIENTS) {
163	            if ((new_socket = accept(server_socket, (struct sockaddr *)&address, &addrlen)) == INVALID_SOCKET) {
164	                printf("Accept failed");
165	                closesocketCheck(server_socket);
166	                WSACleanup();
167	                exit(EXIT_FAILURE);
168	            }
169	            client_sockets[num_clients++] = new_socket;
170	            printf("Client %d connected\n", num_clients);
171	        }
172	
173	        // Step 6) send the NCCL ID to all clients
174	        send_nccl_id_to_clients_windows(&nccl_id, client_sockets, num_clients);
175	        printf("NCCL ID sent to all clients\n");
176	
177	        closesocketCheck(server_socket);
178	    } else {
179	        int num_connection_attempts = 5;
180	        int time_to_sleep = 2;
181	        SOCKET client_socket;
182	        struct sockaddr_in serv_addr;
183	
184	        // Step 1) create a client TCP socket
185	        if ((client_socket = socket(AF_INET, SOCK_STREAM, 0)) == INVALID_SOCKET) {
186	            printf("Socket creation error");
187	            WSACleanup();
188	            exit(EXIT_FAILURE);
189	        }
190	
191	        // Step 2) set the server address and port
192	        serv_addr.sin_family = AF_INET;
193	        serv_addr.sin_port = htons(SERVER_PORT);
194	        if (inet_pton(AF_INET, server_ip, &serv_addr.sin_addr) <= 0) {
195	            printf("Invalid address or address not supported");
196	            closesocketCheck(client_socket);
197	            WSACleanup();
198	            exit(EXIT_FAILURE);
199	        }
200	
201	        // Step 3) Try to connect to the server - retry up to `num_connection_attempts` times if the connection fails
202	        while (connect(client_socket, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) == SOCKET_ERROR) {
203	            printf("%d Connection failed, retrying in %d seconds\n", result->process_rank, time_to_sleep);
204	            if (--num_connection_attempts == 0) {
205	                printf("Failed to connect to the server\n");
206	                closesocketCheck(client_socket);
207	                WSACleanup();
208	                exit(EXIT_FAILURE);
209	            }
210	            Sleep(time_to_sleep * 1000);
211	        }
212	
213	        // Step 4) receive the NCCL ID from the server
214	        if (recv(client_socket, (char *)&nccl_id, sizeof(nccl_id), 0) <= 0) {
215	            printf("Failed to receive nccl_id");
216	            closesocketCheck(client_socket);
217	            WSACleanup();
218	            exit(EXIT_FAILURE);
219	        }
220	
221	        printf("Received NCCL ID\n");
222	        closesocketCheck(client_socket);
223	    }
224	
225	    WSACleanup();
226	    return nccl_id;
227	}
