336	ncclUniqueId get_nccl_id_via_fs(MultiGpuConfig* result, char* fs_path) {
337	    // Works assuming that the filesystem is shared among all processes
338	    ncclUniqueId nccl_id;
339	    FILE* idFile;
340	    static char filename[1024];
341	    snprintf(filename, sizeof(filename), "%s/ncclUniqueId.sync", fs_path);
342	
343	    if (result->process_rank != 0) {  // client processse should wait for the server to write to the file
344	        // This is a naive and not 100% robust way to synchronize the processes but it should work almost always
345	        sleep(2);
346	    }
347	
348	    if (result->process_rank == 0) {
349	        ncclCheck(ncclGetUniqueId(&nccl_id));
350	        idFile = fopen(filename, "wb");
351	        assert(idFile != NULL);
352	        fwriteCheck(&nccl_id, sizeof(nccl_id), 1, idFile);
353	        fcloseCheck(idFile);
354	    } else {
355	        // Other ranks wait until the file is available and read the unique ID
356	        do {
357	            sleep(1);  // 1 second
358	            idFile = fopen(filename, "rb");
359	            if (idFile != NULL) break;
360	        } while (idFile == NULL);
361	        freadCheck(&nccl_id, sizeof(nccl_id), 1, idFile);
362	        fcloseCheck(idFile);
363	    }
364	
365	    return nccl_id;
366	}
