368	#ifdef USE_MPI
369	// Determine which GPU this process should use.
370	// Processes on the same machines use different GPU indicies. Processes on other machines don't.
371	// Copied from NCCL examples: https://docs.nvidia.com/deeplearning/nccl/user-guide/docs/examples.html#example-2-one-device-per-process-or-thread
372	int multi_gpu_get_local_device_idx(int process_rank, int num_processes) {
373	    char hostname[1024];
374	    hostname[1023] = '\0';
375	    // All processes on the same machine will share the same hostname.
376	    gethostname(hostname, 1023);
377	    for (int i=0; i < 1024; i++) {
378	        if (hostname[i] == '.') {
379	            hostname[i] = '\0';
380	            break;
381	        }
382	    }
383	    uint64_t hostname_hash = 5381u;
384	    for (int c = 0; hostname[c] != '\0'; c++){ hostname_hash = ((hostname_hash << 5u) + hostname_hash) ^ hostname[c]; }
385	
386	    // Distribute all hostname hashes to all processes.
387	    uint64_t* all_hostsname_hashes = (uint64_t*)malloc(num_processes * sizeof(uint64_t));
388	    all_hostsname_hashes[process_rank] = hostname_hash;
389	    mpiCheck(MPI_Allgather(MPI_IN_PLACE, 0, MPI_DATATYPE_NULL, all_hostsname_hashes, sizeof(uint64_t), MPI_BYTE, MPI_COMM_WORLD));
390	
391	    // Identify which GPU we need to use.
392	    int local_device_idx = 0;
393	    for (int current_process = 0; current_process < num_processes; ++current_process) {
394	        if (current_process == process_rank) {
395	        // Found my gpu, local_device_idx now has my target GPU index.
396	        break;
397	        }
398	        if (all_hostsname_hashes[current_process] == all_hostsname_hashes[process_rank]) {
399	        // This process ID runs on the same machine, but it's not me, skip this GPU
400	        local_device_idx++;
401	        }
402	    }
403	
404	    free(all_hostsname_hashes);
405	    return local_device_idx;
406	}
407	#endif
