411	MultiGpuConfig multi_gpu_config_init(int num_processes, int process_rank, int gpus_per_node, char* server_ip, char* fs_path, char* init_method) {
412	#ifdef MULTI_GPU
413	    MultiGpuConfig result;
414	    ncclUniqueId nccl_id;
415	    // Get nccl_id using MPI, TCP, or FS (file system synchronization) methods
416	    // On newer slurm versions (slurm-wlm package) PMIx is disabled so we can not use MPI for NCCL init in multi node setup
417	    if (strcmp(init_method, "mpi") == 0) {
418	        #ifdef USE_MPI
419	        mpiCheck(MPI_Init(NULL, NULL));
420	        mpiCheck(MPI_Comm_rank(MPI_COMM_WORLD, &result.process_rank));
421	        mpiCheck(MPI_Comm_size(MPI_COMM_WORLD, &result.num_processes));
422	        result.local_device_idx = multi_gpu_get_local_device_idx(result.process_rank, result.num_processes);
423	        if (result.process_rank == 0) {
424	            ncclCheck(ncclGetUniqueId(&nccl_id));
425	        }
426	        mpiCheck(MPI_Bcast(&nccl_id, sizeof(nccl_id), MPI_BYTE, 0, MPI_COMM_WORLD));
427	        #else
428	        printf("MPI support is disabled. Please enable MPI support to use MPI-based NCCL-init method.\n");
429	        exit(EXIT_FAILURE);
430	        #endif
431	    } else {
432	        result.process_rank = process_rank;
433	        result.num_processes = num_processes;
434	        result.local_device_idx = process_rank % gpus_per_node;
435	        if (strcmp(init_method, "tcp") == 0) {
436	            #ifdef _WIN32
437	            nccl_id = get_nccl_id_via_tcp_windows(&result, server_ip);
438	            #else
439	            nccl_id = get_nccl_id_via_tcp(&result, server_ip);
440	            #endif
441	        } else if (strcmp(init_method, "fs") == 0) {
442	            nccl_id = get_nccl_id_via_fs(&result, fs_path);
443	        } else {
444	            printf("Invalid NCCL-init method\n");
445	            exit(EXIT_FAILURE);
446	        }
447	    }
448	    cudaCheck(cudaSetDevice(result.local_device_idx));
449	    ncclCheck(ncclCommInitRank(&result.nccl_comm, result.num_processes, nccl_id, result.process_rank));
450	    cudaCheck(cudaStreamCreate(&result.nccl_stream));
451	    // event without timing for maximum performance
452	    cudaCheck(cudaEventCreate(&result.compute_nccl_sync, cudaEventDisableTiming));
453	    nvtxNameCudaStreamA(result.nccl_stream, "nccl stream");
454	    nvtxNameCudaEventA(result.compute_nccl_sync, "nccl compute sync");
455	    cudaCheck(cudaMallocManaged(&result.unified_buffer, sizeof(float)));
456	    return result;
457	#else
458	    printf("Multi-GPU support is disabled. Using a single GPU.\n");
459	    cudaCheck(cudaSetDevice(0));
460	    MultiGpuConfig result;
461	    result.process_rank = 0;
462	    result.num_processes = 1;
463	    result.local_device_idx = 0;
464	    return result;
465	#endif
466	}
