480	void multi_gpu_barrier(const MultiGpuConfig* config) {
481	#ifdef MULTI_GPU
482	    if (config->num_processes > 1) {
483	        ncclCheck(ncclAllReduce(config->unified_buffer, config->unified_buffer, sizeof(float), ncclFloat, ncclSum, config->nccl_comm, config->nccl_stream));
484	    }
485	    cudaCheck(cudaDeviceSynchronize());
486	#endif
