489	// Offset and size of a tensor shard
490	typedef struct {
491	    ptrdiff_t offset;
492	    size_t size;
493	} ShardInfo;
494	
495	// Get info about sharding for a tensor of elements many numbers
496	ShardInfo multi_gpu_get_shard_offset(size_t elements, const MultiGpuConfig* config, int shard_at_stage) {
497	    const int nproc = config->num_processes;
498	    if(config->zero_stage >= shard_at_stage) {
499	        if (elements % nproc != 0) {
500	            fprintf(stderr, "Number of elements %zu must be a multiple of the number of processes %d\n", elements, nproc);
501	            exit(EXIT_FAILURE);
502	        }
503	        return {(ptrdiff_t) (config->process_rank * (elements / nproc)), elements / nproc};
504	    } else {
505	        return {0, elements};
506	    }
507	}
