788	void gpt2_backward_and_reduce(GPT2 *model, int* inputs, const int* targets, int grad_accum_steps, int micro_step) {
789	    if(model->grads_memory == nullptr) {
790	        fprintf(stderr, "Need to allocate gradients before backward");
791	        exit(EXIT_FAILURE);
792	    }
793	    NVTX_RANGE_FN();
794	    bool last_step = micro_step == grad_accum_steps - 1;
795	    // on the first micro-step zero the gradients, as we're about to += accumulate into them
796	    if (micro_step == 0) {
797	        // there are currently two state vars during the gradient accumulation inner loop:
798	        // 1) the losses accumulate += into acts.losses, reset here
799	        // 2) the gradients accumulate += into grads_memory, reset here
800	        cudaCheck(cudaMemsetAsync(model->acts.losses, 0, model->batch_size * model->seq_len * sizeof(float), main_stream));
801	        cudaCheck(cudaMemsetAsync(model->grads_memory, 0, model->num_parameters * sizeof(floatX), main_stream));
802	    }
803	
804	    // convenience shortcuts, size_t instead of int so that pointer arithmetics don't overflow
805	    const size_t B = model->batch_size;
806	    const size_t T = model->seq_len;
807	    const size_t V = model->config.vocab_size;
808	    const size_t Vp = model->config.padded_vocab_size;
809	    const size_t L = model->config.num_layers;
810	    const size_t NH = model->config.num_heads;
811	    const size_t C = model->config.channels;
812	
813	    ParameterTensors params = model->params; // for brevity
814	    ParameterTensors grads = model->grads;
815	    ActivationTensors acts = model->acts;
816	
817	    // accumulate the losses inside acts.losses, and kick off the backward pass inside the fused classifier
818	    NvtxRange classifier_and_loss_range("classifier_and_loss");
819	    const float dloss = 1.0f / (float)(B * T * grad_accum_steps); // results in the uniform average loss over all elements
820	    cudaCheck(cudaMemcpy(model->targets, targets, B * T * sizeof(int), cudaMemcpyHostToDevice));
821	    tokenCheck(targets, B*T, V);
822	    fused_classifier(acts.output, acts.losses, dloss, model->targets, B, T, V, Vp, True, main_stream);
823	
824	    // backward pass: go in the reverse order of the forward pass, and call backward() functions
825	
826	    // reset residual stream gradients (put here to work with gradient accumulation)
827	    floatX* dresidual = (floatX*)model->acts.scratch_btc; // the main buffer holding the gradient in the backward pass
828	    cudaCheck(cudaMemset(dresidual, 0, B * T * C * sizeof(floatX)));
829	
830	    // re-use the output buffer of the forward pass as a scratchpad during backward pass
831	    float*  scratchF = (float*)acts.output;
832	    floatX* scratchX = (floatX*)acts.output;
833	
834	    // we kick off the chain rule by filling in dlosses with 1.0f/(B*T)
835	    // this was done in the fused classifier kernel as last step of forward pass
836	    // technically that is a small, inline backward() pass of calculating
837	    // total, final loss as the mean over all losses over all (B,T) positions in the batch
838	    // next: backward the classifier matmul
839	    matmul_backward(model->acts.scratch_bt4c, grads.wte, NULL, acts.output, acts.lnf, params.wte, NULL, B, T, C, Vp, main_stream);
840	    // backward the final layernorm
841	    floatX* residual = acts.residual3 + (L-1) * B * T * C; // last residual is in residual3
842	    layernorm_backward(dresidual, grads.lnfw, grads.lnfb, scratchF, model->acts.scratch_bt4c, residual, params.lnfw, acts.lnf_mean, acts.lnf_rstd, B, T, C, main_stream);
843	
844	    // from this point on, we no longer need the values stored in the last residual, so we can reuse that memory as generic
845	    // scratch for backward computations
846	    floatX* dl_btc = residual;
847	
848	    // now backward all the layers
849	    for (int l = L-1; l >= 0; l--) {
850	        NvtxRange layer_range("Layer", l);
851	
852	        residual = l == 0 ? acts.encoded : acts.residual3 + (l-1) * B * T * C;
853	
854	        // get the pointers of the weights for this layer
855	        floatX* l_ln1w = params.ln1w + l * C;
856	        floatX* l_ln1b = params.ln1b + l * C;
857	        floatX* l_qkvw = params.qkvw + l * 3*C * C;
858	        floatX* l_attprojw = params.attprojw + l * C * C;
859	        floatX* l_ln2w = params.ln2w + l * C;
860	        floatX* l_ln2b = params.ln2b + l * C;
861	        floatX* l_fcw = params.fcw + l * 4*C * C;
862	        floatX* l_fcprojw = params.fcprojw + l * C * 4*C;
863	        // get the pointers of the gradients of the weights for this layer
864	        floatX* dl_ln1w = grads.ln1w + l * C;
865	        floatX* dl_ln1b = grads.ln1b + l * C;
866	        floatX* dl_qkvw = grads.qkvw + l * 3*C * C;
867	        floatX* dl_qkvb = grads.qkvb + l * 3*C;
868	        floatX* dl_attprojw = grads.attprojw + l * C * C;
869	        floatX* dl_attprojb = grads.attprojb + l * C;
870	        floatX* dl_ln2w = grads.ln2w + l * C;
871	        floatX* dl_ln2b = grads.ln2b + l * C;
872	        floatX* dl_fcw = grads.fcw + l * 4*C * C;
873	        floatX* dl_fcb = grads.fcb + l * 4*C;
874	        floatX* dl_fcprojw = grads.fcprojw + l * C * 4*C;
875	        floatX* dl_fcprojb = grads.fcprojb + l * C;
876	        // get the pointers of the activations for this layer
877	        floatX* l_ln1 = (model->recompute < 2) ? acts.ln1 + l * B * T * C : acts.lnf;
878	        float* l_ln1_mean = acts.ln1_mean + l * B * T;
879	        float* l_ln1_rstd = acts.ln1_rstd + l * B * T;
880	        floatX* l_qkvr = acts.qkvr + l * B * T * 3*C;
881	        floatX* l_atty = acts.atty + l * B * T * C;
882	        floatX* l_residual2 = acts.residual2 + l * B * T * C;
883	        floatX* l_ln2 = (model->recompute < 2) ? acts.ln2 + l * B * T * C : acts.lnf;
884	        float* l_ln2_mean = acts.ln2_mean + l * B * T;
885	        float* l_ln2_rstd = acts.ln2_rstd + l * B * T;
886	        floatX* l_fch_pre_gelu = acts.fch + l * B * T * 4*C;
887	        floatX* l_fch_gelu = (model->recompute < 1) ? acts.fch_gelu + l * B * T * 4*C : acts.fch_gelu;
888	        // get the pointers of the gradients of the activations for this layer
889	        // notice that there is no l *, because we just have a single copy, and keep
890	        // re-using this memory in every Transformer block as we calculate backward pass
891	
892	        floatX* dl_bt4c = (floatX*)model->acts.scratch_bt4c;
893	
894	        // start the backward pass for this layer
895	        if(model->recompute >= 1) {
896	            // recompute >= 1 means we recompute gelu. in this case,
897	            // l_fch_gelu is just a buffer, so re-compute the gelu from l_fch here
898	            gelu_forward(l_fch_gelu, l_fch_pre_gelu, B*T*4*C, main_stream);
899	        }
900	        matmul_backward(dl_bt4c, dl_fcprojw, dl_fcprojb, dresidual, l_fch_gelu, l_fcprojw, scratchF, B, T, 4*C, C, main_stream, l_fch_pre_gelu, model->gelu_fusion);
901	        if(model->recompute >= 2) {
902	            // same as gelu above, l_ln1 and l_ln2 are just buffers if recompute >= 2, recompute them here on demand
903	            layernorm_forward(l_ln2, l_ln2_mean, l_ln2_rstd, l_residual2, l_ln2w, l_ln2b, B, T, C, main_stream);
904	        }
905	        matmul_backward(dl_btc, dl_fcw, dl_fcb, dl_bt4c, l_ln2, l_fcw, scratchF, B, T, C, 4 * C, main_stream);
906	        // layernorm backward does += to the dresidual, so it correctly accumulates grad from the MLP block above
907	        layernorm_backward(dresidual, dl_ln2w, dl_ln2b, scratchF, dl_btc, l_residual2, l_ln2w, l_ln2_mean, l_ln2_rstd, B, T, C, main_stream);
908	        matmul_backward(dl_btc, dl_attprojw, dl_attprojb, dresidual, l_atty, l_attprojw, scratchF, B, T, C, C, main_stream);
909	
910	        #ifdef ENABLE_CUDNN
911	        float* l_att = (float*)acts.att + l * B * NH * T; // cuDNN needs a smaller FP32 tensor
912	        attention_backward_cudnn(dl_bt4c, dl_btc, l_qkvr, l_atty, (float*)l_att, B, T, NH, C, main_stream);
913	        #else
914	        floatX* l_att = acts.att + l * B * NH * T * T;
915	        // we need B x T x (4)C buffers. l_atty and l_fch aren't needed anymore at this point, so reuse their memory
916	        floatX* buffer_a = l_atty;
917	        floatX* buffer_b = l_fch_pre_gelu;        // this is B x T x 4C, so even larger than what we need
918	        attention_backward(dl_bt4c, buffer_b, scratchX, buffer_a, dl_btc, l_qkvr, l_att, B, T, C, NH, main_stream);
919	        #endif
920	        if(model->recompute >= 2) {
921	            layernorm_forward(l_ln1, l_ln1_mean, l_ln1_rstd, residual, l_ln1w, l_ln1b, B, T, C, main_stream);
922	        }
923	        // QKV parameter gradients
924	        matmul_backward(dl_btc, dl_qkvw, dl_qkvb, dl_bt4c, l_ln1, l_qkvw, scratchF, B, T, C, 3 * C, main_stream);
925	        // layernorm backward does += to dresidual, so it correctly accumulates gradient for the Attention block above
926	        layernorm_backward(dresidual, dl_ln1w, dl_ln1b, scratchF, dl_btc, residual, l_ln1w, l_ln1_mean, l_ln1_rstd, B, T, C, main_stream);
927	
928	        // Accumulate gradients from this layer in a background stream.
929	        if(last_step) {
930	            floatX* const pointers[] = {
931	                dl_ln1w, dl_ln1b,
932	                dl_qkvw, dl_qkvb,
933	                dl_attprojw, dl_attprojb,
934	                dl_ln2w, dl_ln2b,
935	                dl_fcw, dl_fcb,
936	                dl_fcprojw, dl_fcprojb
937	            };
938	            const size_t nelem[] = {
939	                C, C,
940	                3 * C * C, 3 * C,
941	                C * C, C,
942	                C, C,
943	                4 * C * C, 4 * C,
944	                C * 4 * C, C
945	            };
946	            multi_gpu_async_reduce_gradient(pointers, nelem, &multi_gpu_config, main_stream);
947	        }
948	    }
949	    encoder_backward(grads.wte, grads.wpe, scratchX, model->workload_indices, model->bucket_info,
950	                     dresidual, model->inputs, inputs, B, T, C, random_u32(&model->rng_state), main_stream);
951	
952	    // Aggregate all gradients that are not part of the transformer blocks
953	    if(last_step) {
954	        // reduce all the losses within the current GPU (across all microsteps)
955	        global_sum_deterministic(model->accumulated_mean_loss, acts.losses, B*T, main_stream);
956	        // reduce loss across GPUs to a single, final float across all microsteps and GPUs
957	        #if MULTI_GPU
958	        ncclCheck(ncclAllReduce(model->accumulated_mean_loss, model->accumulated_mean_loss, sizeof(float), ncclFloat, ncclAvg, multi_gpu_config.nccl_comm, main_stream));
959	        #endif
960	        cudaCheck(cudaMemcpyAsync(&model->mean_loss, model->accumulated_mean_loss, sizeof(float), cudaMemcpyDeviceToHost, main_stream));
961	        // reduce the gradients for non-transformer block parameters
962	        floatX* const pointers[] = {grads.wte, grads.wpe, grads.lnfw, grads.lnfb};
963	        const size_t nelem[] = {Vp * C, T * C, C, C};
964	        multi_gpu_async_reduce_gradient(pointers, nelem, &multi_gpu_config, main_stream);
965	    }
966	
967	    cudaCheck(cudaDeviceSynchronize());
968	    if(last_step) {
969	        model->mean_loss /= B*T*grad_accum_steps;
970	    } else {
971	        model->mean_loss = -1.f; // no loss available yet
972	    }
973	}
974	
975	// Gets the offset of a specific tensor for a specific layer in the GPT2 model
976	// layer_id is ignored for weights that are not part of a transformer block
977	ShardInfo gpt2_get_tensor_at_layer(const GPT2 *model, int layer_id, int param_tensor_id) {
978	    // first offset our way to the parameter tensor start
979	    ptrdiff_t offset = 0;
980	    for (int i = 0; i < param_tensor_id; i++) {
981	        offset += (ptrdiff_t)model->param_elements[i];
982	    }
983	    size_t size = model->param_elements[param_tensor_id] ;
984	    // if we are in the transformer block, we need to additionally offset by the layer id
985	    if(2 <= param_tensor_id && param_tensor_id <= 13) {
986	        size /= model->config.num_layers;
987	        offset += (ptrdiff_t)(layer_id * size);
988	    }
989	    return {offset, size};
990	}
991	
992	float gpt2_calculate_grad_norm(GPT2 *model, MultiGpuConfig* multi_gpu_config) {
993	    NVTX_RANGE_FN();
994	    floatX* grads_memory = (floatX*)model->grads_memory;
995	
996	    // repurposing this buffer (which isn't needed now) to write grad norm into it
997	    float* grad_norm_squared = (float*)model->acts.output;
998	    float grad_norm_squared_cpu = 0.0f;
999	
1000	    int num_slices[2] = {1, model->config.num_layers};
1001	    int max_num_block_sums = get_max_num_block_sums(num_slices, 2);
1002	    if (multi_gpu_config->zero_stage == 1) {
1003	        // because of the ncclReduceScatter() in backward,
1004	        // grads_memory only contains the averaged gradients at the local shards,
1005	        // so we only calculate the grad norm at the grads_memory belonging to the local shards
1006	        for (int i = 0; i < NUM_PARAMETER_TENSORS; i++) {
1007	            ShardInfo tensor = gpt2_get_tensor_at_layer(model, 0, i);
1008	            ShardInfo shard = multi_gpu_get_shard_offset(tensor.size, multi_gpu_config, 1);
1009	            ptrdiff_t offset = tensor.offset + shard.offset;
1010	            bool is_first_pass = (i == 0);
1011	            if((i < 2 || i > 13)) {
1012	                global_norm_squared(grad_norm_squared, grads_memory + offset, shard.size, 0, 1,
1013	                                    max_num_block_sums, is_first_pass, main_stream);
1014	            } else {
1015	                global_norm_squared(grad_norm_squared, grads_memory + offset, shard.size, tensor.size, model->config.num_layers,
1016	                                    max_num_block_sums, is_first_pass, main_stream);
1017	            }
1018	        }
1019	        global_sum_deterministic(grad_norm_squared, grad_norm_squared, max_num_block_sums, main_stream);
1020	#if MULTI_GPU
1021	        // further sum the (partial) squared norm across all GPUs
1022	        ncclCheck(ncclAllReduce(grad_norm_squared, grad_norm_squared, sizeof(float), ncclFloat, ncclSum, multi_gpu_config->nccl_comm, main_stream));
1023	#endif
1024	    } else {
1025	        // in regular DDP, backward has averaged the gradients across all GPUs
1026	        // so each GPU can compute the squared norm over the whole grad vector, with no added comms needed
1027	        global_norm_squared(grad_norm_squared, grads_memory, model->num_parameters, 0, 1, max_num_block_sums, true, main_stream);
1028	        global_sum_deterministic(grad_norm_squared, grad_norm_squared, max_num_block_sums, main_stream);
1029	    }
1030	    cudaCheck(cudaMemcpy(&grad_norm_squared_cpu, grad_norm_squared, sizeof(float), cudaMemcpyDeviceToHost));
1031	    float grad_norm_cpu = sqrtf(grad_norm_squared_cpu);
1032	    return grad_norm_cpu;
1033	}
1034	
1035	void gpt2_update(GPT2 *model, float learning_rate, float beta1, float beta2, float eps, float weight_decay, float grad_scale, int t,
1036	                 MultiGpuConfig* multi_gpu_config, bool init_from_master_only=false) {
1037	    // update the model parameters using the AdamW optimizer
1038	    // keep in mind that optimizer sharding (ZeRO-1) assigns different parameters to different GPUs
1039	    // so we may not be responsible for the entire parameter tensor
1040	    // also, this function was very simple a while back but become very complex, only because we want to
1041	    // selectively weight decay some, but not all tensors :(
1042	    // TODO: revisit and probably refactor this entire function
1043	    NVTX_RANGE_FN();
1044	    if(model->grads_memory == nullptr || model->m_memory == nullptr || model->v_memory == nullptr) {
1045	        fprintf(stderr, "Need to allocate optimizer state before update");
1046	        exit(EXIT_FAILURE);
